5	use App\Enums\AuditAction;
6	use App\Http\Controllers\Controller;
7	use App\Http\Resources\UserResource;
8	use App\Services\AuditService;
9	use Illuminate\Http\JsonResponse;
10	use Illuminate\Http\Request;
11	use Illuminate\Support\Facades\Auth;
12	use Illuminate\Support\Facades\Hash;
13	
14	class AuthController extends Controller
15	{
16	    public function login(Request $request, AuditService $audit): JsonResponse
17	    {
18	        $request->validate([
19	            'username' => 'required|string',
20	            'password' => 'required|string',
21	        ]);
22	
23	        if (!Auth::attempt(['username' => $request->username, 'password' => $request->password])) {
24	            $audit->log(AuditAction::LoginFailed, null, [
25	                'username' => $request->username,
26	            ], 'warning');
27	
28	            return response()->json(['error' => 'Invalid credentials.'], 401);
29	        }
30	
31	        $user = Auth::user();
32	        $request->session()->regenerate();
33	
34	        $audit->log(AuditAction::Login, $user->id);
35	
36	        return response()->json([
37	            'user' => new UserResource($user),
38	        ]);
39	    }
40	
41	    public function me(Request $request): UserResource
42	    {
43	        return new UserResource($request->user());
44	    }
45	
46	    public function logout(Request $request, AuditService $audit): JsonResponse
47	    {
48	        $audit->log(AuditAction::Logout, $request->user()->id);
49	
50	        Auth::guard('web')->logout();
51	        $request->session()->invalidate();
52	        $request->session()->regenerateToken();
53	
54	        return response()->json(['message' => 'Logged out.']);
55	    }
56	
57	    public function stepUpVerify(Request $request, AuditService $audit): JsonResponse
58	    {
59	        $request->validate([
60	            'password' => 'required|string',
61	        ]);
62	
63	        $user = $request->user();
64	
65	        if (!Hash::check($request->password, $user->password)) {
66	            $audit->log(AuditAction::StepUpFailed, $user->id, [], 'warning');
67	            return response()->json(['error' => 'Invalid password.'], 403);
68	        }
69	
70	        $audit->log(AuditAction::StepUpVerified, $user->id);
71	
72	        \App\Http\Middleware\StepUpAuth::elevate();
73	
74	        return response()->json([
75	            'message' => 'Step-up verified.',
76	            'elevated_until' => now()->addMinutes(5)->toIso8601String(),
77	        ]);
78	    }
79	}
