268	        $existingData = $duplicate['existing_data'];
269	
270	        // Check updated_at for incremental sync
271	        $incomingUpdatedAt = $mapped['updated_at'] ?? null;
272	        $existingUpdatedAt = $existingData['updated_at'] ?? null;
273	
274	        if ($incomingUpdatedAt && $existingUpdatedAt && $incomingUpdatedAt <= $existingUpdatedAt) {
275	            return ['status' => 'skipped', 'reason' => 'existing_is_newer'];
276	        }
277	
278	        // Overwrite with incoming data
279	        return $this->updateRecord($existingId, $mapped, $entity);
280	    }
