440	    private function toCsv(Collection $data): string
441	    {
442	        if ($data->isEmpty()) {
443	            return '';
444	        }
445	
446	        $output = fopen('php://temp', 'r+');
447	        fputcsv($output, array_keys($data->first()));
448	
449	        foreach ($data as $row) {
450	            fputcsv($output, $row);
451	        }
452	
453	        rewind($output);
454	        $csv = stream_get_contents($output);
455	        fclose($output);
456	
457	        return $csv;
458	    }
