11	
12	class AttemptLogin
13	{
14	    private const MAX_ATTEMPTS = 5;
15	    private const LOCKOUT_MINUTES = 15;
16	
17	    public function __construct(
18	        private AuditService $audit,
19	        private CaptchaService $captcha,
20	    ) {}
21	
22	    public function execute(
23	        string $username,
24	        string $password,
25	        ?string $captchaInput = null,
26	    ): LoginResult {
27	        $user = User::where('username', $username)->first();
28	
29	        // Check if user exists
30	        if ($user === null) {
31	            $this->audit->log(AuditAction::LoginFailed, null, [
32	                'username' => $username,
33	                'reason' => 'user_not_found',
34	            ], 'warning');
35	
36	            return LoginResult::failed('Invalid username or password.');
37	        }
38	
39	        // Check if account is active
40	        if (!$user->is_active) {
41	            $this->audit->log(AuditAction::LoginFailed, $user->id, [
42	                'reason' => 'account_disabled',
43	            ], 'warning');
44	
45	            return LoginResult::failed('Your account has been disabled. Contact an administrator.');
46	        }
47	
48	        // Check lockout
49	        if ($user->isLocked()) {
50	            $minutesLeft = (int) now()->diffInMinutes($user->locked_until, false);
51	
52	            return LoginResult::locked("Account is locked. Try again in {$minutesLeft} minute(s).");
53	        }
54	
55	        // Check if CAPTCHA is required
56	        if ($user->requiresCaptcha() && $captchaInput !== null) {
57	            if (!$this->captcha->verify($captchaInput)) {
58	                $this->audit->log(AuditAction::CaptchaFailed, $user->id, [], 'warning');
59	
60	                return LoginResult::captchaRequired('Invalid CAPTCHA. Please try again.');
61	            }
62	        }
63	
64	        if ($user->requiresCaptcha() && $captchaInput === null) {
65	            return LoginResult::captchaRequired('Please complete the CAPTCHA to continue.');
66	        }
67	
68	        // Verify password
69	        if (!Hash::check($password, $user->password)) {
70	            $user->increment('failed_login_attempts');
71	
72	            if ($user->failed_login_attempts >= self::MAX_ATTEMPTS) {
73	                $user->update(['locked_until' => now()->addMinutes(self::LOCKOUT_MINUTES)]);
74	                $this->audit->log(AuditAction::AccountLocked, $user->id, [
75	                    'attempts' => $user->failed_login_attempts,
76	                    'locked_until' => $user->locked_until->toIso8601String(),
77	                ], 'critical');
78	
79	                return LoginResult::locked('Account locked for ' . self::LOCKOUT_MINUTES . ' minutes due to too many failed attempts.');
80	            }
81	
82	            $this->audit->log(AuditAction::LoginFailed, $user->id, [
83	                'attempts' => $user->failed_login_attempts,
84	            ], 'warning');
85	
86	            $needsCaptcha = $user->requiresCaptcha();
87	
88	            return $needsCaptcha
89	                ? LoginResult::captchaRequired('Invalid username or password.')
90	                : LoginResult::failed('Invalid username or password.');
91	        }
92	
93	        // Detect login anomaly (new device fingerprint)
94	        $currentFingerprint = md5(request()->userAgent() . request()->ip());
95	        if ($user->device_fingerprint !== null && $user->device_fingerprint !== $currentFingerprint) {
96	            $this->audit->log(AuditAction::LoginAnomaly, $user->id, [
97	                'previous_fingerprint' => $user->device_fingerprint,
98	                'new_fingerprint' => $currentFingerprint,
99	            ], 'warning');
100	        }
101	
102	        // Reset failed attempts and login
103	        $user->update([
104	            'failed_login_attempts' => 0,
105	            'locked_until' => null,
106	            'device_fingerprint' => $currentFingerprint,
107	        ]);
108	
109	        Auth::login($user);
110	        session()->regenerate();
111	
112	        $this->audit->log(AuditAction::Login, $user->id);
113	
114	        // Check if password rotation is needed
115	        if ($user->isPasswordExpired()) {
116	            return LoginResult::passwordExpired();
117	        }
118	
119	        return LoginResult::success();
120	    }
121	}
