12	use Illuminate\Support\Facades\DB;
13	
14	class ReservationService
15	{
16	    public function __construct(
17	        private AuditService $audit,
18	        private PenaltyConfigService $penaltyConfig,
19	    ) {}
20	
21	    public function createReservation(User $user, int $timeSlotId): Reservation
22	    {
23	        if (!$user->isLearner()) {
24	            throw new \DomainException('Only learners can create reservations.');
25	        }
26	
27	        if ($user->isBookingFrozen()) {
28	            throw new \DomainException('Your booking privileges are frozen until ' . $user->booking_frozen_until->format('M d, Y'));
29	        }
30	
31	        $expiryMinutes = $this->penaltyConfig->getExpiryMinutes();
32	
33	        return DB::transaction(function () use ($user, $timeSlotId, $expiryMinutes) {
34	            // Pessimistic lock on the time slot
35	            $slot = TimeSlot::lockForUpdate()->findOrFail($timeSlotId);
36	
37	            if (!$slot->hasAvailability()) {
38	                throw new \DomainException('This time slot is no longer available.');
39	            }
40	
41	            if (!$slot->isFuture()) {
42	                throw new \DomainException('Cannot book a past time slot.');
43	            }
44	
45	            // Check for existing reservation on same slot
46	            $existing = Reservation::where('user_id', $user->id)
47	                ->where('time_slot_id', $timeSlotId)
48	                ->whereNotIn('status', [
49	                    ReservationStatus::Cancelled->value,
50	                    ReservationStatus::NoShow->value,
51	                ])
52	                ->exists();
53	
54	            if ($existing) {
55	                throw new \DomainException('You already have a reservation for this time slot.');
56	            }
57	
58	            $reservation = Reservation::create([
59	                'user_id' => $user->id,
60	                'service_id' => $slot->service_id,
61	                'time_slot_id' => $timeSlotId,
62	                'status' => ReservationStatus::Pending,
63	                'expires_at' => now()->addMinutes($expiryMinutes),
64	            ]);
65	
66	            $slot->increment('booked_count');
67	
68	            // Dispatch expiry job
69	            ExpireUnconfirmedReservation::dispatch($reservation->id)
70	                ->delay(now()->addMinutes($expiryMinutes));
71	
72	            $this->audit->log(AuditAction::ReservationCreated, $user->id, [
73	                'reservation_id' => $reservation->id,
74	                'time_slot_id' => $timeSlotId,
75	            ]);
76	
77	            return $reservation;
78	        });
79	    }
80	
81	    public function confirm(Reservation $reservation): Reservation
82	    {
83	        if ($reservation->status !== ReservationStatus::Pending) {
84	            throw new \DomainException('Only pending reservations can be confirmed.');
85	        }
86	
87	        if ($reservation->expires_at && $reservation->expires_at->isPast()) {
88	            throw new \DomainException('This reservation has expired.');
89	        }
90	
91	        $reservation->update([
92	            'status' => ReservationStatus::Confirmed,
93	            'confirmed_at' => now(),
94	            'expires_at' => null,
95	        ]);
96	
97	        $this->audit->log(AuditAction::ReservationConfirmed, $reservation->user_id, [
98	            'reservation_id' => $reservation->id,
99	        ]);
100	
101	        return $reservation;
102	    }
103	
104	    public function cancel(Reservation $reservation, ?string $reason = null): Reservation
105	    {
106	        if (!$reservation->canCancel()) {
107	            throw new \DomainException('This reservation cannot be cancelled.');
108	        }
109	
110	        return DB::transaction(function () use ($reservation, $reason) {
111	            $reservation->update([
112	                'status' => ReservationStatus::Cancelled,
113	                'cancelled_at' => now(),
114	                'cancellation_reason' => $reason,
115	            ]);
116	
117	            // Release the slot
118	            $reservation->timeSlot->decrement('booked_count');
119	
120	            // Apply late cancellation penalty (fee OR points, not both — admin-configurable)
121	            if (!$reservation->isFreeCancellation()) {
122	                $mode = $this->penaltyConfig->getMode();
123	                $feeAmount = $mode === 'fee' ? $this->penaltyConfig->getCancelFee() : 0;
124	                $pointsDeducted = $mode === 'points' ? $this->penaltyConfig->getCancelPoints() : 0;
125	                $reasonSuffix = $mode === 'fee'
126	                    ? sprintf('$%.2f fee applied.', $this->penaltyConfig->getCancelFee())
127	                    : sprintf('%d points deducted.', $this->penaltyConfig->getCancelPoints());
128	
129	                Penalty::create([
130	                    'user_id' => $reservation->user_id,
131	                    'reservation_id' => $reservation->id,
132	                    'type' => 'late_cancellation',
133	                    'fee_amount' => $feeAmount,
134	                    'points_deducted' => $pointsDeducted,
135	                    'reason' => 'Cancelled less than ' . $this->penaltyConfig->getFreeCancelHours() . ' hours before start time. ' . $reasonSuffix,
136	                    'created_at' => now(),
137	                ]);
138	            }
139	
140	            $this->audit->log(AuditAction::ReservationCancelled, $reservation->user_id, [
141	                'reservation_id' => $reservation->id,
142	                'free_cancellation' => $reservation->isFreeCancellation(),
143	            ]);
144	
145	            return $reservation;
146	        });
147	    }
148	
149	    public function reschedule(Reservation $reservation, int $newTimeSlotId): Reservation
150	    {
151	        if (!$reservation->canCancel()) {
152	            throw new \DomainException('This reservation cannot be rescheduled.');
153	        }
154	
155	        return DB::transaction(function () use ($reservation, $newTimeSlotId) {
156	            // Cancel old reservation (no penalty for reschedule)
157	            $reservation->update([
158	                'status' => ReservationStatus::Cancelled,
159	                'cancelled_at' => now(),
160	                'cancellation_reason' => 'Rescheduled',
161	            ]);
162	            $reservation->timeSlot->decrement('booked_count');
163	
164	            // Create new reservation
165	            return $this->createReservation($reservation->user, $newTimeSlotId);
166	        });
167	    }
168	
169	    public function checkIn(Reservation $reservation): Reservation
170	    {
171	        if (!$reservation->canCheckIn()) {
172	            throw new \DomainException('Check-in is not available at this time.');
173	        }
174	
175	        $isLate = $reservation->timeSlot->isLateArrival();
176	
177	        $reservation->update([
178	            'status' => $isLate
179	                ? ReservationStatus::PartialAttendance
180	                : ReservationStatus::CheckedIn,
181	            'checked_in_at' => now(),
182	        ]);
183	
184	        $this->audit->log(AuditAction::ReservationCheckedIn, $reservation->user_id, [
185	            'reservation_id' => $reservation->id,
186	            'late' => $isLate,
187	        ]);
188	
189	        return $reservation;
190	    }
191	
192	    public function checkOut(Reservation $reservation): Reservation
193	    {
194	        if (!in_array($reservation->status, [ReservationStatus::CheckedIn, ReservationStatus::PartialAttendance])) {
195	            throw new \DomainException('Cannot check out a reservation that is not checked in.');
196	        }
197	
198	        // Partial attendance cannot extend into next slot
199	        if ($reservation->status === ReservationStatus::PartialAttendance) {
200	            $reservation->update([
201	                'checked_out_at' => min(now(), $reservation->timeSlot->end_time),
202	                'status' => ReservationStatus::Completed,
203	            ]);
204	        } else {
205	            $reservation->update([
206	                'checked_out_at' => now(),
207	                'status' => ReservationStatus::Completed,
208	            ]);
209	        }
210	
211	        return $reservation;
212	    }
213	
214	    public function expireIfPending(int $reservationId): void
215	    {
216	        $reservation = Reservation::find($reservationId);
217	
218	        if (!$reservation || $reservation->status !== ReservationStatus::Pending) {
219	            return;
220	        }
221	
222	        DB::transaction(function () use ($reservation) {
223	            $reservation->update([
224	                'status' => ReservationStatus::Cancelled,
225	                'cancelled_at' => now(),
226	                'cancellation_reason' => 'Expired: not confirmed within ' . $this->penaltyConfig->getExpiryMinutes() . ' minutes.',
227	            ]);
228	
229	            $reservation->timeSlot->decrement('booked_count');
230	        });
231	    }
232	
233	    public function processNoShows(): int
234	    {
235	        $processed = 0;
236	
237	        // Find all confirmed reservations where the check-in window has closed
238	        $noShows = Reservation::where('status', ReservationStatus::Confirmed)
239	            ->whereHas('timeSlot', function ($q) {
240	                $q->where('start_time', '<', now()->subMinutes(10));
241	            })
242	            ->get();
243	
244	        foreach ($noShows as $reservation) {
245	            DB::transaction(function () use ($reservation) {
246	                $reservation->update(['status' => ReservationStatus::NoShow]);
247	
248	                Penalty::create([
249	                    'user_id' => $reservation->user_id,
250	                    'reservation_id' => $reservation->id,
251	                    'type' => 'no_show',
252	                    'fee_amount' => 0,
253	                    'points_deducted' => 0,
254	                    'reason' => 'Did not check in within the allowed window.',
255	                    'created_at' => now(),
256	                ]);
257	            });
258	
259	            $processed++;
260	        }
261	
262	        // Check breach thresholds and freeze accounts
263	        $this->evaluateFreezes();
264	
265	        return $processed;
266	    }
267	
268	    private function evaluateFreezes(): void
269	    {
270	        $windowDays = $this->penaltyConfig->getNoShowWindowDays();
271	        $threshold = $this->penaltyConfig->getNoShowThreshold();
272	        $freezeDays = $this->penaltyConfig->getFreezeDays();
273	
274	        $windowStart = now()->subDays($windowDays);
275	
276	        $breachCounts = Penalty::where('type', 'no_show')
277	            ->where('created_at', '>=', $windowStart)
278	            ->selectRaw('user_id, count(*) as breach_count')
279	            ->groupBy('user_id')
280	            ->having('breach_count', '>=', $threshold)
281	            ->pluck('breach_count', 'user_id');
282	
283	        foreach ($breachCounts as $userId => $count) {
284	            $user = User::find($userId);
285	            if ($user && !$user->isBookingFrozen()) {
286	                $user->update([
287	                    'booking_frozen_until' => now()->addDays($freezeDays),
288	                ]);
289	
290	                $this->audit->log(AuditAction::BookingFreeze, $userId, [
291	                    'breaches' => $count,
292	                    'frozen_until' => $user->booking_frozen_until->toIso8601String(),
293	                ], 'critical');
294	            }
295	        }
296	    }
297	}
