5	use Closure;
6	use Illuminate\Http\Request;
7	use Symfony\Component\HttpFoundation\Response;
8	
9	class StepUpAuth
10	{
11	    private const SESSION_KEY = 'step_up_verified_at';
12	    private const ELEVATION_MINUTES = 5;
13	
14	    public function handle(Request $request, Closure $next): Response
15	    {
16	        $verifiedAt = session(self::SESSION_KEY);
17	
18	        if ($verifiedAt === null || now()->diffInMinutes($verifiedAt) >= self::ELEVATION_MINUTES) {
19	            if ($request->expectsJson()) {
20	                return response()->json([
21	                    'error' => 'step_up_required',
22	                    'message' => 'Please re-enter your password to continue.',
23	                ], 403);
24	            }
25	
26	            session(['step_up_redirect' => $request->fullUrl()]);
27	
28	            return redirect()->route('auth.step-up');
29	        }
30	
31	        return $next($request);
32	    }
33	
34	    public static function elevate(): void
35	    {
36	        session([self::SESSION_KEY => now()]);
37	    }
38	
39	    public static function isElevated(): bool
40	    {
41	        $verifiedAt = session(self::SESSION_KEY);
42	
43	        return $verifiedAt !== null && now()->diffInMinutes($verifiedAt) < self::ELEVATION_MINUTES;
44	    }
45	}
