38	    /**
39	     * Accessing export without step-up must redirect to verification.
40	     */
41	    public function test_export_without_elevation_redirects_to_step_up(): void
42	    {
43	        $this->actingAs($this->admin);
44	
45	        $response = $this->get('/admin/export');
46	        $response->assertRedirect(route('auth.step-up'));
47	    }
48	
