64	     * Step-up elevation expires after 5 minutes.
65	     */
66	    public function test_step_up_expires_after_5_minutes(): void
67	    {
68	        $this->actingAs($this->admin);
69	
70	        // Simulate elevation from 6 minutes ago
71	        session(['step_up_verified_at' => now()->subMinutes(6)]);
72	
73	        $response = $this->get('/admin/export');
74	        $response->assertRedirect(route('auth.step-up'));
75	    }
