77	    /**
78	     * Step-up verification component accepts correct password.
79	     */
80	    public function test_step_up_verification_with_correct_password(): void
81	    {
82	        $this->actingAs($this->admin);
83	
84	        Livewire::test(\App\Livewire\Auth\StepUpVerification::class)
85	            ->set('password', 'Admin123!@#456')
86	            ->call('verify')
87	            ->assertRedirect(route('dashboard'));
