138	            'username' => 'editor',
139	            'name' => 'Editor',
140	            'email' => 'editor@test.local',
141	            'password' => 'Editor123!@#456',
142	            'role' => UserRole::Editor,
143	            'password_updated_at' => now(),
144	            'is_active' => true,
145	        ]);
