16	
17	    // ── EXPORT ──
18	
19	    public function exportServices(string $format, array $options = []): string
20	    {
21	        $query = Service::with('tags')->active();
22	
23	        if (!empty($options['since'])) {
24	            $query->where('updated_at', '>=', $options['since']);
25	        }
26	
27	        $services = $query->get()->map(function (Service $s) {
28	            return [
29	                'id' => $s->id,
30	                'title' => $s->title,
31	                'slug' => $s->slug,
32	                'description' => $s->description,
33	                'service_type' => $s->service_type,
34	                'eligibility_notes' => $s->eligibility_notes,
35	                'target_audience' => implode('|', $s->target_audience ?? []),
36	                'price' => $s->price,
37	                'category' => $s->category,
38	                'tags' => $s->tags->pluck('name')->implode('|'),
39	                'is_active' => $s->is_active ? 'true' : 'false',
40	                'created_at' => $s->created_at->toIso8601String(),
41	                'updated_at' => $s->updated_at->toIso8601String(),
42	            ];
43	        });
44	
45	        return $format === 'json'
46	            ? $this->toJson($services)
47	            : $this->toCsv($services);
48	    }
49	
50	    public function exportUsers(string $format, array $options = []): string
51	    {
52	        $query = User::query();
53	
54	        if (!empty($options['since'])) {
55	            $query->where('updated_at', '>=', $options['since']);
56	        }
57	
58	        $includeSensitive = !empty($options['include_sensitive']);
59	
60	        $users = $query->get()->map(function (User $u) use ($includeSensitive) {
61	            $row = [
62	                'id' => $u->id,
63	                'username' => $u->username,
64	                'name' => $u->name,
65	                'email' => $u->email,
66	                'role' => $u->role->value,
67	                'is_active' => $u->is_active ? 'true' : 'false',
68	                'created_at' => $u->created_at->toIso8601String(),
69	                'updated_at' => $u->updated_at->toIso8601String(),
70	            ];
71	
72	            // Only include decrypted sensitive fields if explicitly mapped by admin
73	            if ($includeSensitive) {
74	                $row['phone'] = $u->phone_encrypted;
75	                $row['external_id'] = $u->external_id_encrypted;
76	            }
77	
78	            // NEVER export password hashes
79	            return $row;
80	        });
81	
82	        return $format === 'json'
83	            ? $this->toJson($users)
84	            : $this->toCsv($users);
85	    }
86	
87	    // ── IMPORT PARSING ──
88	
89	    public function parseFile(string $path, string $format): array
90	    {
91	        return $format === 'json'
92	            ? $this->parseJson($path)
93	            : $this->parseCsv($path);
94	    }
95	
96	    public function detectHeaders(string $path, string $format): array
97	    {
98	        $rows = $this->parseFile($path, $format);
99	
100	        if (empty($rows)) {
101	            return [];
102	        }
103	
104	        return array_keys($rows[0]);
105	    }
106	
107	    public function getDestinationFields(string $entity): array
108	    {
109	        return match ($entity) {
110	            'services' => [
111	                'title', 'description', 'service_type', 'eligibility_notes',
112	                'target_audience', 'price', 'category', 'tags', 'is_active',
113	            ],
114	            'users' => [
115	                'username', 'name', 'email', 'role', 'is_active',
116	                'phone_encrypted', 'external_id_encrypted',
117	            ],
118	            default => [],
119	        };
120	    }
121	
122	    // ── DUPLICATE DETECTION ──
123	
124	    public function detectDuplicates(array $row, string $entity, array $fieldMapping): Collection
125	    {
126	        $conflicts = collect();
127	
128	        if ($entity === 'services') {
129	            $conflicts = $this->detectServiceDuplicates($row, $fieldMapping);
130	        } elseif ($entity === 'users') {
131	            $conflicts = $this->detectUserDuplicates($row, $fieldMapping);
132	        }
133	
134	        return $conflicts;
135	    }
136	
137	    private function detectServiceDuplicates(array $row, array $fieldMapping): Collection
138	    {
139	        $conflicts = collect();
140	        $mappedTitle = $this->getMappedValue($row, $fieldMapping, 'title');
141	
142	        if ($mappedTitle === null) {
143	            return $conflicts;
144	        }
145	
146	        $normalizedTitle = $this->normalizeTitle($mappedTitle);
147	
148	        // Exact ID match
149	        $mappedId = $this->getMappedValue($row, $fieldMapping, 'id');
150	        if ($mappedId !== null) {
151	            $existing = Service::find($mappedId);
152	            if ($existing) {
153	                $conflicts->push([
154	                    'existing_id' => $existing->id,
155	                    'existing_data' => $existing->toArray(),
156	                    'similarity_score' => 1.0,
157	                    'match_type' => 'exact_id',
158	                ]);
159	                return $conflicts;
160	            }
161	        }
162	
163	        // Trigram similarity on normalized title
164	        $similar = DB::select(
165	            "SELECT id, title, similarity(lower(title), ?) as score
166	             FROM services
167	             WHERE similarity(lower(title), ?) >= ?
168	             ORDER BY score DESC
169	             LIMIT 5",
170	            [$normalizedTitle, $normalizedTitle, self::SIMILARITY_THRESHOLD]
171	        );
172	
173	        foreach ($similar as $match) {
174	            $existing = Service::find($match->id);
175	            if ($existing) {
176	                $conflicts->push([
177	                    'existing_id' => $existing->id,
178	                    'existing_data' => $existing->toArray(),
179	                    'similarity_score' => round((float) $match->score, 4),
180	                    'match_type' => 'title_similarity',
181	                ]);
182	            }
183	        }
184	
185	        return $conflicts;
186	    }
187	
188	    private function detectUserDuplicates(array $row, array $fieldMapping): Collection
189	    {
190	        $conflicts = collect();
191	
192	        // Exact username match
193	        $username = $this->getMappedValue($row, $fieldMapping, 'username');
194	        if ($username !== null) {
195	            $existing = User::where('username', $username)->first();
196	            if ($existing) {
197	                $conflicts->push([
198	                    'existing_id' => $existing->id,
199	                    'existing_data' => $existing->makeVisible([])->toArray(),
200	                    'similarity_score' => 1.0,
201	                    'match_type' => 'exact_id',
202	                ]);
203	                return $conflicts;
204	            }
205	        }
206	
207	        // Exact email match
208	        $email = $this->getMappedValue($row, $fieldMapping, 'email');
209	        if ($email !== null) {
210	            $existing = User::where('email', $email)->first();
211	            if ($existing) {
212	                $conflicts->push([
213	                    'existing_id' => $existing->id,
214	                    'existing_data' => $existing->makeVisible([])->toArray(),
215	                    'similarity_score' => 1.0,
216	                    'match_type' => 'exact_id',
217	                ]);
218	            }
219	        }
220	
221	        return $conflicts;
222	    }
223	
224	    // ── ROW PROCESSING ──
225	
226	    public function processRow(
227	        array $row,
228	        string $entity,
229	        array $fieldMapping,
230	        string $conflictStrategy,
231	        ImportBatch $batch,
232	    ): array {
233	        $mapped = $this->applyMapping($row, $fieldMapping);
234	        $duplicates = $this->detectDuplicates($row, $entity, $fieldMapping);
235	
236	        if ($duplicates->isNotEmpty()) {
237	            $best = $duplicates->first();
238	
239	            if ($conflictStrategy === 'skip') {
240	                return ['status' => 'skipped', 'reason' => 'duplicate'];
241	            }
242	
243	            if ($conflictStrategy === 'prefer_newest') {
244	                return $this->resolvePreferNewest($mapped, $best, $entity, $batch);
245	            }
246	
247	            // admin_override — create conflict for manual resolution
248	            ImportConflict::create([
249	                'import_batch_id' => $batch->id,
250	                'entity' => $entity,
251	                'existing_id' => $best['existing_id'],
252	                'incoming_data' => $mapped,
253	                'existing_data' => $best['existing_data'],
254	                'similarity_score' => $best['similarity_score'],
255	                'match_type' => $best['match_type'],
256	            ]);
257	
258	            return ['status' => 'conflict', 'conflict_id' => $best['existing_id']];
259	        }
260	
261	        // No duplicates — create new record
262	        return $this->createRecord($mapped, $entity);
263	    }
264	
265	    private function resolvePreferNewest(array $mapped, array $duplicate, string $entity, ImportBatch $batch): array
266	    {
267	        $existingId = $duplicate['existing_id'];
268	        $existingData = $duplicate['existing_data'];
269	
270	        // Check updated_at for incremental sync
271	        $incomingUpdatedAt = $mapped['updated_at'] ?? null;
272	        $existingUpdatedAt = $existingData['updated_at'] ?? null;
273	
274	        if ($incomingUpdatedAt && $existingUpdatedAt && $incomingUpdatedAt <= $existingUpdatedAt) {
275	            return ['status' => 'skipped', 'reason' => 'existing_is_newer'];
276	        }
277	
278	        // Overwrite with incoming data
279	        return $this->updateRecord($existingId, $mapped, $entity);
280	    }
281	
282	    private function createRecord(array $data, string $entity): array
283	    {
284	        try {
285	            if ($entity === 'services') {
286	                $this->createServiceFromImport($data);
287	            } elseif ($entity === 'users') {
288	                $this->createUserFromImport($data);
289	            }
290	
291	            return ['status' => 'created'];
292	        } catch (\Exception $e) {
293	            return ['status' => 'error', 'error' => $e->getMessage()];
294	        }
295	    }
296	
297	    private function updateRecord(int $id, array $data, string $entity): array
298	    {
299	        try {
300	            if ($entity === 'services') {
301	                $service = Service::findOrFail($id);
302	                $updateData = array_filter($data, fn($v) => $v !== null && $v !== '');
303	                unset($updateData['id'], $updateData['created_at'], $updateData['updated_at'], $updateData['tags']);
304	                $service->update($updateData);
305	
306	                if (!empty($data['tags'])) {
