460	    private function parseCsv(string $path): array
461	    {
462	        $rows = [];
463	        $handle = fopen($path, 'r');
464	
465	        if ($handle === false) {
466	            throw new \RuntimeException('Cannot open file: ' . $path);
467	        }
468	
469	        $headers = fgetcsv($handle);
470	
471	        if ($headers === false) {
472	            fclose($handle);
473	            return [];
474	        }
475	
476	        // Normalize headers
477	        $headers = array_map(fn($h) => trim(strtolower($h)), $headers);
478	
479	        while (($line = fgetcsv($handle)) !== false) {
480	            if (count($line) === count($headers)) {
481	                $rows[] = array_combine($headers, $line);
482	            }
483	        }
484	
485	        fclose($handle);
486	
487	        return $rows;
488	    }
