3	namespace App\Services;
4	
5	use Illuminate\Support\Facades\Session;
6	use Illuminate\Support\Str;
7	
8	class CaptchaService
9	{
10	    private const SESSION_KEY = 'captcha_code';
11	    private const CODE_LENGTH = 6;
12	    private const IMAGE_WIDTH = 200;
13	    private const IMAGE_HEIGHT = 60;
14	
15	    public function generate(): string
16	    {
17	        $code = $this->generateCode();
18	        Session::put(self::SESSION_KEY, strtolower($code));
19	
20	        return $this->renderImage($code);
21	    }
22	
23	    public function verify(string $input): bool
24	    {
25	        $stored = Session::pull(self::SESSION_KEY);
26	
27	        if ($stored === null) {
28	            return false;
29	        }
30	
31	        return strtolower(trim($input)) === $stored;
32	    }
33	
34	    private function generateCode(): string
35	    {
36	        $characters = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789';
37	
38	        return Str::substr(str_shuffle($characters), 0, self::CODE_LENGTH);
39	    }
40	
41	    private function renderImage(string $code): string
42	    {
43	        $image = imagecreatetruecolor(self::IMAGE_WIDTH, self::IMAGE_HEIGHT);
44	
45	        $bgColor = imagecolorallocate($image, 245, 245, 245);
46	        imagefill($image, 0, 0, $bgColor);
47	
48	        // Add noise lines
49	        for ($i = 0; $i < 8; $i++) {
50	            $lineColor = imagecolorallocate(
51	                $image,
52	                random_int(150, 220),
53	                random_int(150, 220),
54	                random_int(150, 220)
