namespace App\Services;

use Illuminate\Http\Request;
use Illuminate\Http\JsonResponse;
use Illuminate\Support\Facades\App;

/**
 * Internal API client that routes Livewire requests through
 * the REST API controller stack (including middleware, validation,
 * and audit logging) without HTTP network overhead.
 *
 * This ensures Livewire and external API consumers share identical
 * validation, authorization, and audit behavior.
 */
class InternalApiClient
{
    public function get(string $uri, array $query = []): array
    {
        return $this->call('GET', $uri, $query);
    }

    public function post(string $uri, array $data = []): array
    {
        return $this->call('POST', $uri, $data);
    }

    public function put(string $uri, array $data = []): array
    {
        return $this->call('PUT', $uri, $data);
    }

    public function delete(string $uri, array $data = []): array
    {
        return $this->call('DELETE', $uri, $data);
    }

    private function call(string $method, string $uri, array $data = []): array
    {
        $uri = '/api/' . ltrim($uri, '/');

        $request = Request::create(
            $uri,
            $method,
            $data,
            request()->cookies->all(),
            [],
            array_merge(request()->server->all(), [
                'HTTP_ACCEPT' => 'application/json',
                'HTTP_X_CSRF_TOKEN' => csrf_token(),
            ]),
        );

        // Share the session and auth state from the current request
        $request->setLaravelSession(request()->session());
        $request->setUserResolver(fn () => auth()->user());

        $response = App::handle($request);

        $status = $response->getStatusCode();
        $body = $response instanceof JsonResponse
            ? $response->getData(true)
            : json_decode($response->getContent(), true) ?? [];

        return [
            'status' => $status,
            'ok' => $status >= 200 && $status < 300,
            'data' => $body['data'] ?? $body,
            'error' => $body['error'] ?? null,
            'message' => $body['message'] ?? null,
            'body' => $body,
        ];
    }
}
"}

