3	namespace App\Jobs;
4	
5	use App\Models\ImportBatch;
6	use App\Services\ImportExportService;
7	use Illuminate\Support\Str;
8	use Illuminate\Bus\Queueable;
9	use Illuminate\Contracts\Queue\ShouldQueue;
10	use Illuminate\Foundation\Bus\Dispatchable;
11	use Illuminate\Queue\InteractsWithQueue;
12	use Illuminate\Queue\SerializesModels;
13	use Illuminate\Support\Facades\Log;
14	
15	class ProcessImportChunk implements ShouldQueue
16	{
17	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
18	
19	    public int $tries = 3;
20	    public int $timeout = 300;
21	
22	    public function __construct(
23	        private int $batchId,
24	        private array $rows,
25	        private int $startIndex,
26	    ) {}
27	
28	    public function handle(ImportExportService $service): void
29	    {
30	        $batch = ImportBatch::find($this->batchId);
31	
32	        if (!$batch || $batch->status === 'failed') {
33	            return;
34	        }
35	
36	        $errors = $batch->error_log ?? [];
37	
38	        foreach ($this->rows as $index => $row) {
39	            $rowNumber = $this->startIndex + $index + 1; // 1-based for display
40	
41	            try {
42	                $result = $service->processRow(
43	                    $row,
44	                    $batch->entity,
45	                    $batch->field_mapping ?? [],
46	                    $batch->conflict_strategy,
47	                    $batch,
48	                );
49	
50	                match ($result['status']) {
51	                    'created', 'updated' => $batch->increment('success_count'),
52	                    'skipped' => null,
53	                    'conflict' => $batch->increment('duplicate_count'),
54	                    'error' => $this->recordError($batch, $errors, $rowNumber, $result['error'] ?? 'Unknown error'),
55	                    default => null,
56	                };
57	            } catch (\Exception $e) {
58	                $this->recordError($batch, $errors, $rowNumber, $e->getMessage());
59	                Log::error("Import row {$rowNumber} failed", [
60	                    'batch_id' => $this->batchId,
61	                    'error' => $e->getMessage(),
62	                ]);
63	            }
64	
65	            $batch->increment('processed_rows');
66	        }
67	
68	        // Update error log
69	        if (!empty($errors)) {
70	            $batch->update(['error_log' => $errors]);
71	        }
72	
73	        // Check if batch is complete
74	        $batch->refresh();
75	        if ($batch->processed_rows >= $batch->total_rows) {
76	            $finalStatus = $batch->error_count > 0 && $batch->success_count === 0
77	                ? 'failed'
78	                : 'completed';
79	
80	            $batch->update([
81	                'status' => $batch->unresolvedConflicts()->count() > 0 ? 'pending_review' : $finalStatus,
82	                'completed_at' => now(),
83	            ]);
84	        }
85	    }
86	
87	    private function recordError(ImportBatch $batch, array &$errors, int $rowNumber, string $message): void
88	    {
89	        $errors[] = [
90	            'row' => $rowNumber,
91	            'error' => Str::limit($message, 500),
92	            'timestamp' => now()->toIso8601String(),
93	        ];
94	        $batch->increment('error_count');
95	    }
