namespace App\Services;

use Illuminate\Http\Request;
use Illuminate\Routing\Router;
use Illuminate\Support\Facades\Route;
use Symfony\Component\HttpFoundation\Response;

/**
 * Internal API client that routes Livewire requests through
 * the REST API controller stack (including validation and
 * audit logging) without HTTP network overhead.
 *
 * This ensures Livewire and external API consumers share identical
 * validation, authorization, and audit behavior by dispatching
 * through the same API route definitions.
 */
class InternalApiClient
{
    public function get(string $uri, array $query = []): array
    {
        return $this->call('GET', $uri, $query);
    }

    public function post(string $uri, array $data = []): array
    {
        return $this->call('POST', $uri, $data);
    }

    public function put(string $uri, array $data = []): array
    {
        return $this->call('PUT', $uri, $data);
    }

    public function delete(string $uri, array $data = []): array
    {
        return $this->call('DELETE', $uri, $data);
    }

    private function call(string $method, string $uri, array $data = []): array
    {
        $uri = '/api/' . ltrim($uri, '/');

        // Build an internal request that carries the current auth/session context
        $currentRequest = request();

        $internalRequest = Request::create(
            $uri,
            $method,
            $data,
            $currentRequest->cookies->all(),
            [],
            $currentRequest->server->all(),
        );

        $internalRequest->headers->set('Accept', 'application/json');

        // Share auth and session from the parent Livewire request
        if ($currentRequest->hasSession()) {
            $internalRequest->setLaravelSession($currentRequest->session());
        }
        $internalRequest->setUserResolver(fn () => auth()->user());

        // Resolve route and dispatch through the controller (bypassing HTTP kernel
        // but still going through route middleware, validation, and controller logic)
        $router = app(Router::class);

        try {
            $response = $router->dispatch($internalRequest);
        } catch (\Illuminate\Auth\AuthenticationException $e) {
            return ['status' => 401, 'ok' => false, 'data' => [], 'error' => 'Unauthenticated.', 'message' => 'Unauthenticated.', 'body' => []];
        } catch (\Illuminate\Auth\Access\AuthorizationException $e) {
            return ['status' => 403, 'ok' => false, 'data' => [], 'error' => 'Forbidden.', 'message' => $e->getMessage(), 'body' => []];
        } catch (\Illuminate\Validation\ValidationException $e) {
            return ['status' => 422, 'ok' => false, 'data' => [], 'error' => 'Validation failed.', 'message' => $e->getMessage(), 'body' => ['errors' => $e->errors()]];
        }

        $status = $response->getStatusCode();
        $content = $response->getContent();
        $body = json_decode($content, true) ?? [];

        return [
            'status' => $status,
            'ok' => $status >= 200 && $status < 300,
            'data' => $body['data'] ?? $body,
            'error' => $body['error'] ?? null,
            'message' => $body['message'] ?? null,
            'body' => $body,
        ];
    }
}
"}

