 * without HTTP network overhead.
 *
 * This ensures Livewire and external API consumers share identical
 * validation and audit behavior by dispatching through the same
 * API controller methods. Auth/session is inherited from the
 * current Livewire request context.
 */
class InternalApiClient
{
    public function get(string $uri, array $query = []): array
    {
        return $this->call('GET', $uri, $query);
    }

    public function post(string $uri, array $data = []): array
    {
        return $this->call('POST', $uri, $data);
    }

    public function put(string $uri, array $data = []): array
    {
        return $this->call('PUT', $uri, $data);
    }

    public function delete(string $uri, array $data = []): array
    {
        return $this->call('DELETE', $uri, $data);
    }

    private function call(string $method, string $uri, array $data = []): array
    {
        $uri = '/api/' . ltrim($uri, '/');

        // Build an internal request that carries the current auth/session context
        $currentRequest = request();

        $internalRequest = Request::create(
            $uri,
            $method,
            $data,
            $currentRequest->cookies->all(),
            [],
            $currentRequest->server->all(),
        );

        $internalRequest->headers->set('Accept', 'application/json');

        // Share auth from the parent Livewire request
        $internalRequest->setUserResolver(fn () => auth()->user());

        // Resolve the matching route and run the controller action directly
        // This skips the global/group middleware (auth already handled by Livewire's
        // web middleware) but runs through the controller's validation + service calls
        $router = app(Router::class);
        $route = $router->getRoutes()->match($internalRequest);

        // Bind route parameters to the request
        $internalRequest->setRouteResolver(fn () => $route);
        $route->bind($internalRequest);

        try {
            $response = $route->run();

            // Handle both Response objects and raw data
            if ($response instanceof \Illuminate\Http\Response || $response instanceof \Illuminate\Http\JsonResponse || $response instanceof \Symfony\Component\HttpFoundation\Response) {
                $status = $response->getStatusCode();
                $content = $response->getContent();
                $body = json_decode($content, true) ?? [];
            } else {
                // Raw data returned (e.g., a Resource)
                $body = json_decode(json_encode($response), true) ?? [];
                $status = 200;
            }
        } catch (\Illuminate\Validation\ValidationException $e) {
            return [
                'status' => 422,
                'ok' => false,
                'data' => [],
                'error' => 'Validation failed.',
                'message' => $e->getMessage(),
                'body' => ['errors' => $e->errors()],
            ];
