                'ok' => false,
                'data' => [],
                'error' => 'Forbidden.',
                'message' => $e->getMessage(),
                'body' => [],
            ];
        } catch (\DomainException $e) {
            return [
                'status' => 422,
                'ok' => false,
                'data' => [],
                'error' => $e->getMessage(),
                'message' => $e->getMessage(),
                'body' => [],
            ];
        }

        return [
            'status' => $status,
            'ok' => $status >= 200 && $status < 300,
            'data' => $body['data'] ?? $body,
            'error' => $body['error'] ?? null,
