                'body' => [],
            ];
        }

        return [
            'status' => $status,
            'ok' => $status >= 200 && $status < 300,
            'data' => $body['data'] ?? $body,
            'error' => $body['error'] ?? null,
            'message' => $body['message'] ?? null,
