109	            'field_mapping' => $this->fieldMapping,
110	            'conflict_strategy' => $this->conflictStrategy,
111	            'status' => 'processing',
112	        ]);
113	
114	        // Parse from the exact stored file path
115	        $fullPath = storage_path('app/' . $batch->stored_path);
