123	        $chunks = array_chunk($rows, self::CHUNK_SIZE);
124	
125	        $startIndex = 0;
126	        foreach ($chunks as $chunk) {
127	            ProcessImportChunk::dispatch($batch->id, $chunk, $startIndex);
128	            $startIndex += count($chunk);
129	        }
130	
131	        $this->step = 'processing';
132	        $this->successMessage = "Import started! Processing {$batch->total_rows} rows in " . count($chunks) . " chunk(s).";
133	    }
