170	    {
171	        $order = ['upload', 'mapping', 'processing', 'review', 'done'];
172	        $currentIndex = array_search($this->step, $order);
173	        $checkIndex = array_search($checkStep, $order);
174	
175	        return $checkIndex < $currentIndex;
176	    }
