            $this->ruleType = $rule->rules['type'] ?? 'string';
            $this->ruleMin = (string) ($rule->rules['min'] ?? '');
            $this->ruleMax = (string) ($rule->rules['max'] ?? '');
            $this->ruleRegex = $rule->rules['regex'] ?? '';
            $this->ruleIsActive = $rule->is_active;
        }
        $this->showRuleForm = true;
    }

