            $this->step = 'processing';
            $data = $response['data'];
            $this->successMessage = "Import started! Processing {$data['total_rows']} rows in {$data['chunks']} chunk(s).";
        } else {
            $this->errorMessage = $response['error'] ?? $response['message'] ?? 'Failed to start processing.';
        }
