3	namespace App\Livewire\Reservations;
4	
5	use App\Enums\ReservationStatus;
6	use App\Models\Reservation;
7	use App\Models\TimeSlot;
8	use App\Services\ReservationService;
9	use Livewire\Component;
10	use Livewire\WithPagination;
11	
12	class ReservationDashboard extends Component
13	{
14	    use WithPagination;
15	
16	    public string $filter = 'upcoming'; // upcoming, past, all
17	    public string $errorMessage = '';
18	    public string $successMessage = '';
19	
20	    // Reschedule state
21	    public ?int $reschedulingReservationId = null;
22	    public ?int $selectedNewSlotId = null;
23	    public array $availableSlots = [];
24	
25	    public function confirm(int $reservationId, ReservationService $service): void
26	    {
27	        $this->clearMessages();
28	
29	        try {
30	            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
31	            $service->confirm($reservation);
32	            $this->successMessage = 'Reservation confirmed!';
33	        } catch (\DomainException $e) {
34	            $this->errorMessage = $e->getMessage();
35	        }
36	    }
37	
38	    public function cancel(int $reservationId, ReservationService $service): void
39	    {
40	        $this->clearMessages();
41	
42	        try {
43	            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
44	            $service->cancel($reservation);
45	            $this->successMessage = 'Reservation cancelled.';
46	        } catch (\DomainException $e) {
47	            $this->errorMessage = $e->getMessage();
48	        }
49	    }
50	
51	    public function checkIn(int $reservationId, ReservationService $service): void
52	    {
53	        $this->clearMessages();
54	
55	        try {
56	            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
57	            $service->checkIn($reservation);
58	            $this->successMessage = 'Checked in successfully!';
59	        } catch (\DomainException $e) {
60	            $this->errorMessage = $e->getMessage();
61	        }
62	    }
63	
64	    public function checkOut(int $reservationId, ReservationService $service): void
65	    {
66	        $this->clearMessages();
67	
68	        try {
69	            $reservation = Reservation::where('user_id', auth()->id())->findOrFail($reservationId);
70	            $service->checkOut($reservation);
71	            $this->successMessage = 'Checked out. Thank you!';
72	        } catch (\DomainException $e) {
73	            $this->errorMessage = $e->getMessage();
74	        }
75	    }
76	
77	    public function startReschedule(int $reservationId): void
78	    {
79	        $this->clearMessages();
80	        $reservation = Reservation::where('user_id', auth()->id())
81	            ->with('service')
82	            ->findOrFail($reservationId);
83	
84	        if (!$reservation->canCancel()) {
85	            $this->errorMessage = 'This reservation cannot be rescheduled.';
86	            return;
87	        }
88	
89	        $this->reschedulingReservationId = $reservationId;
90	        $this->selectedNewSlotId = null;
91	
92	        // Load available time slots for the same service
93	        $this->availableSlots = TimeSlot::where('service_id', $reservation->service_id)
94	            ->where('id', '!=', $reservation->time_slot_id)
95	            ->available()
96	            ->orderBy('start_time')
97	            ->limit(20)
98	            ->get()
99	            ->map(fn ($slot) => [
100	                'id' => $slot->id,
101	                'label' => $slot->start_time->format('D, M d, Y g:i A') . ' - ' . $slot->end_time->format('g:i A'),
102	                'available' => $slot->capacity - $slot->booked_count,
103	            ])
104	            ->toArray();
105	
106	        if (empty($this->availableSlots)) {
107	            $this->errorMessage = 'No other time slots are available for this service.';
108	            $this->reschedulingReservationId = null;
109	        }
110	    }
111	
112	    public function cancelReschedule(): void
113	    {
114	        $this->reschedulingReservationId = null;
115	        $this->selectedNewSlotId = null;
116	        $this->availableSlots = [];
117	    }
118	
119	    public function confirmReschedule(ReservationService $service): void
120	    {
121	        $this->clearMessages();
122	
123	        if (!$this->reschedulingReservationId || !$this->selectedNewSlotId) {
124	            $this->errorMessage = 'Please select a new time slot.';
125	            return;
126	        }
127	
128	        try {
129	            $reservation = Reservation::where('user_id', auth()->id())
130	                ->findOrFail($this->reschedulingReservationId);
131	            $service->reschedule($reservation, $this->selectedNewSlotId);
132	            $this->successMessage = 'Reservation rescheduled successfully!';
133	            $this->cancelReschedule();
134	        } catch (\DomainException $e) {
135	            $this->errorMessage = $e->getMessage();
136	        }
137	    }
138	
139	    private function clearMessages(): void
140	    {
141	        $this->errorMessage = '';
142	        $this->successMessage = '';
143	    }
144	
145	    public function render()
146	    {
147	        $query = Reservation::where('user_id', auth()->id())
148	            ->with(['service', 'timeSlot', 'penalties'])
149	            ->orderByDesc('created_at');
150	
151	        if ($this->filter === 'upcoming') {
152	            $query->whereIn('status', [
153	                ReservationStatus::Pending->value,
154	                ReservationStatus::Confirmed->value,
155	            ])->whereHas('timeSlot', fn($q) => $q->where('start_time', '>=', now()));
156	        } elseif ($this->filter === 'past') {
157	            $query->whereIn('status', [
158	                ReservationStatus::Completed->value,
159	                ReservationStatus::Cancelled->value,
160	                ReservationStatus::NoShow->value,
161	                ReservationStatus::PartialAttendance->value,
162	            ]);
163	        }
164	
165	        return view('livewire.reservations.reservation-dashboard', [
166	            'reservations' => $query->paginate(10),
167	        ])->layout('components.layouts.app', ['title' => 'My Reservations']);
168	    }
169	}
