11	class ExportManager extends Component
12	{
13	    public string $entity = 'services';
14	    public string $format = 'csv';
15	    public bool $includeSensitive = false;
16	    public bool $incrementalOnly = false;
17	    public string $sinceDate = '';
18	    public string $errorMessage = '';
19	
20	    public function export(ImportExportService $service, AuditService $audit): StreamedResponse|null
21	    {
22	        $this->errorMessage = '';
23	
24	        $options = [];
25	
26	        if ($this->incrementalOnly && $this->sinceDate) {
27	            $options['since'] = $this->sinceDate;
28	        }
29	
30	        if ($this->includeSensitive) {
31	            $options['include_sensitive'] = true;
32	        }
33	
34	        try {
35	            $content = match ($this->entity) {
36	                'services' => $service->exportServices($this->format, $options),
37	                'users' => $service->exportUsers($this->format, $options),
38	                default => throw new \InvalidArgumentException('Invalid entity'),
39	            };
40	
41	            $audit->log(AuditAction::DataExport, auth()->id(), [
42	                'entity' => $this->entity,
43	                'format' => $this->format,
44	                'include_sensitive' => $this->includeSensitive,
45	                'incremental' => $this->incrementalOnly,
46	            ]);
47	
48	            $filename = $this->entity . '_export_' . now()->format('Y-m-d_His') . '.' . $this->format;
49	            $mimeType = $this->format === 'json' ? 'application/json' : 'text/csv';
50	
51	            return response()->streamDownload(function () use ($content) {
52	                echo $content;
53	            }, $filename, [
54	                'Content-Type' => $mimeType,
55	            ]);
56	        } catch (\Exception $e) {
57	            $this->errorMessage = 'Export failed: ' . $e->getMessage();
58	            return null;
59	        }
60	    }
61	
62	    public function render()
63	    {
64	        return view('livewire.admin.export-manager')
65	            ->layout('components.layouts.app', ['title' => 'Export Data']);
66	    }
67	}
